/**
 * @summary Subscribe to the newsletter
 */
export const getSubscribeNewsletterUrl = () => {
  return `/api/newsletter/subscribe`;
};

export const subscribeNewsletter = async (
  newsletterSubscribeRequest: NewsletterSubscribeRequest,
  options?: RequestInit,
): Promise<NewsletterSubscribeResponse> => {
  return customFetch<NewsletterSubscribeResponse>(getSubscribeNewsletterUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(newsletterSubscribeRequest),
  });
};

export const getSubscribeNewsletterMutationOptions = <
  TError = ErrorType<
    BadRequestResponse | RateLimitResponse | InternalErrorResponse
  >,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof subscribeNewsletter>>,
    TError,
    { data: BodyType<NewsletterSubscribeRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof subscribeNewsletter>>,
  TError,
  { data: BodyType<NewsletterSubscribeRequest> },
  TContext
> => {
  const mutationKey = ["subscribeNewsletter"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof subscribeNewsletter>>,
    { data: BodyType<NewsletterSubscribeRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return subscribeNewsletter(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

export type SubscribeNewsletterMutationResult = NonNullable<
  Awaited<ReturnType<typeof subscribeNewsletter>>
>;
export type SubscribeNewsletterMutationBody =
  BodyType<NewsletterSubscribeRequest>;
export type SubscribeNewsletterMutationError = ErrorType<
  BadRequestResponse | RateLimitResponse | InternalErrorResponse
>;

/**
 * @summary Subscribe to the newsletter
 */
export const useSubscribeNewsletter = <
  TError = ErrorType<
    BadRequestResponse | RateLimitResponse | InternalErrorResponse
  >,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof subscribeNewsletter>>,
    TError,
    { data: BodyType<NewsletterSubscribeRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationResult<
  Awaited<ReturnType<typeof subscribeNewsletter>>,
  TError,
  { data: BodyType<NewsletterSubscribeRequest> },
  TContext
> => {
  return useMutation(getSubscribeNewsletterMutationOptions(options));
};
